import java.util.ArrayList;
import java.util.Collections;

public class LambdaDemo {

    @FunctionalInterface
    interface Greeting {
        String greet(String name);
    }

    public static void main(String[] args) {
        // 1. Lambda as Runnable
        Runnable r = () -> System.out.println("Hello from lambda thread!");
        new Thread(r).start();

        // 2. Lambda as Comparator — sort strings by length
        ArrayList<String> words = new ArrayList<>();
        words.add("banana");
        words.add("kiwi");
        words.add("apple");
        words.add("fig");

        Collections.sort(words, (a, b) -> a.length() - b.length());
        System.out.println("Sorted by length: " + words);

        // 3. Lambda with custom functional interface
        Greeting formal = name -> "Good day, " + name + ".";
        Greeting casual = name -> "Hey, " + name + "!";

        System.out.println(formal.greet("Alice"));
        System.out.println(casual.greet("Bob"));
    }
}

import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class StreamsDemo {
    public static void main(String[] args) {
        List<Integer> salaries = Arrays.asList(35000, 72000, 45000, 90000, 28000, 60000, 82000);

        // 1. Filter salaries above 50000, collect to list, print
        List<Integer> highEarners = salaries.stream()
            // your filter here
            .collect(Collectors.toList());
        System.out.println("High earners: " + highEarners);

        // 2. Calculate average salary
        double avg = salaries.stream()
            // use mapToInt and average()
            .getAsDouble();
        System.out.printf("Average salary: %.2f%n", avg);

        // 3. Find count of salaries above 50000
        long count = salaries.stream()
            // filter and count
            ;
        System.out.println("Count above 50000: " + count);
    }
}

import java.util.Optional;

public class OptionalDemo {

    static Optional<String> findUserById(int id) {
        if (id == 1) return Optional.of("Alice");
        if (id == 2) return Optional.of("Bob");
        return Optional.empty(); // user not found
    }

    public static void main(String[] args) {
        // Case 1: user exists
        Optional<String> user1 = findUserById(1);
        System.out.println("Found: " + user1.isPresent());
        System.out.println("Name: " + user1.get());

        // Case 2: user not found — use orElse()
        Optional<String> user3 = findUserById(99);
        String name = user3.orElse("Guest");
        System.out.println("Name or default: " + name);

        // Case 3: transform with map() — get length of name if present
        Optional<Integer> nameLength = findUserById(2).map(n -> n.length());
        System.out.println("Bob's name length: " + nameLength.orElse(0));
    }
}
